--
-- Table structure for table `pets`
--

DROP TABLE IF EXISTS `pets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `pets` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `pet_type` varchar(50) DEFAULT '',
  `breed` varchar(255) DEFAULT '',
  `age` varchar(50) DEFAULT '',
  `gender` varchar(20) DEFAULT '',
  `color` varchar(100) DEFAULT '',
  `weight` varchar(20) DEFAULT '',
  `pet_code` varchar(50) DEFAULT '',
  `vaccination` varchar(50) DEFAULT '',
  `description` text DEFAULT NULL,
  `image_url` text DEFAULT NULL,
  `contact_info` text DEFAULT NULL,
  `source_url` varchar(500) DEFAULT '',
  `status` varchar(20) DEFAULT 'available',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `source_url` (`source_url`),
  KEY `idx_pet_type` (`pet_type`),
  KEY `idx_breed` (`breed`),
  KEY `idx_pet_code` (`pet_code`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
